// Do not edit this file as it will be overwritten if HAMR codegen is rerun

static inline std::string _messageToString(const temp_control_mixed_u_ros_cpp_pkg_interfaces::msg::Temperature& msg) {
    std::ostringstream oss;
    oss << "Temperature{degrees: " << msg.degrees.data << ", unit: " << enumToString(msg.unit) << "}";
    return oss.str();
}

static inline std::string _messageToString(const temp_control_mixed_u_ros_cpp_pkg_interfaces::msg::SetPoint& msg) {
    std::ostringstream oss;
    oss << "SetPoint{low: " << "Temperature{degrees: " << msg.low.degrees.data << ", unit: " << enumToString(msg.low.unit) << "}" << ", high: " << "Temperature{degrees: " << msg.high.degrees.data << ", unit: " << enumToString(msg.high.unit) << "}" << "}";
    return oss.str();
}

